def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 10):
            weight = 1 / (j ** 1.5)
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
        if capacity < item * 1.2:
            score *= 1.5
        elif capacity < item * 2:
            score *= 1.3
        elif capacity > item * 4:
            score *= 0.7
        elif capacity > item * 3:
            score *= 0.85
        if score < 0.1:
            score += 0.05
        elif score > 1.5:
            score -= 0.2
        if i % 3 == 0:
            score *= 1.05
        elif i % 5 == 0:
            score *= 0.95
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 10
        elif priorities[i] == max_priority:
            priorities[i] *= 1.1
        elif priorities[i] == min_priority:
            priorities[i] *= 0.9
    return priorities
